args.sparql:
SELECT ?artist WHERE {
  ?song wdt:P1476 "Two Pints of Lager and a Packet of Crisps"@en .
  ?song wdt:P161 ?artist .
}

SELECT ?artist ?artistLabel WHERE {
  ?song wdt:P1476 "Two Pints of Lager and a Packet of Crisps"@en .
  ?song wdt:P161 ?artist .
  ?artist rdfs:label ?artistLabel FILTER (lang(?artistLabel) = "en")
}

SELECT ?artist ?artistLabel WHERE {
  ?song wdt:P1476 "Two Pints of Lager and a Packet of Crisps"@en .
  ?song wdt:P161 ?artist .
  ?artist rdfs:label ?artistLabel FILTER (lang(?artistLabel) = "en")
}
